B.abR={n1:0,n10:1,n20:2,n30:3,n40:4,n50:5}
B.akP=new A.aT("Con \u0111\u01b0\u1eddng nh\u1eadp m\xf4n n\u0103m x\u01b0a gi\u1edd \u0111\u1ea7y tro t\xe0n. T\u1eeb \u0111\xe2y, ta kh\xf4ng c\xf2n \u0111\u01b0\u1eddng lui.","Ta b\u01b0\u1edbc ti\u1ebfp kh\xf4ng ph\u1ea3i \u0111\u1ec3 n\u1ed5i danh; cha m\u1eb9 ta \u0111\xe3 y\xean ngh\u1ec9 v\xec tu\u1ed5i gi\xe0, v\xe0 l\u1eddi d\u1eb7n cu\u1ed1i c\u1ee7a h\u1ecd l\xe0 \u0111\u1eebng b\u1ecf m\u1eb7c ng\u01b0\u1eddi y\u1ebfu gi\u1eefa lo\u1ea1n \u0111\u1eddi.",null)
B.alq=new A.aT("B\u01b0\u1edbc qua \u0111\xe2y l\xe0 m\xe1u, l\xf9i l\u1ea1i l\xe0 h\u1ed1i h\u1eadn.","Ta s\u1ed1ng s\xf3t, nh\u01b0ng kh\xf4ng th\u1ec3 ti\u1ebfp t\u1ee5c s\u1ed1ng v\xf4 ngh\u0129a.",null)
B.akJ=new A.aT("Ng\u01b0\u01a1i \u0111\xe1nh v\xec danh, ta \u0111\xe1nh v\xec \u0111\u01b0\u1eddng v\u1ec1 nh\xe0.","M\u1ed7i k\u1ebb g\u1ee5c xu\u1ed1ng \u0111\u1ec1u t\u1eebng l\xe0 ai \u0111\xf3 c\u1ee7a m\u1ed9t gia \u0111\xecnh.",null)
B.al5=new A.aT("Tro t\xe0n b\xe1m v\xe0o \xe1o, kh\xf4ng g\u1ed9t \u0111\u01b0\u1ee3c b\u1eb1ng n\u01b0\u1edbc.","Ta kh\xf4ng c\xf2n t\xecm th\u1eafng thua, ta t\xecm l\u1ed1i \u0111\u1ec3 ng\u01b0\u1eddi kh\xe1c kh\u1ecfi m\u1ea5t nh\xe0.",null)
B.akR=new A.aT("N\u1ebfu ta b\u1ecf ch\u1ea1y n\u1eefa, s\u1ebd l\u1ea1i c\xf3 ng\u01b0\u1eddi ch\u1ebft thay ta.","N\u1ed7i s\u1ee3 v\u1eabn c\xf2n, nh\u01b0ng ch\xe2n ta kh\xf4ng l\xf9i n\u1eefa.",null)
B.akK=new A.aT("Ng\u01b0\u01a1i th\u1eafng v\xe0i tr\u1eadn nh\u1ecf r\u1ed3i t\u01b0\u1edfng \u0111\xe3 hi\u1ec3u lo\u1ea1n th\u1ebf? H\xe3y tr\u1ea3 l\u1eddi b\u1eb1ng m\xe1u c\u1ee7a ch\xednh ng\u01b0\u01a1i.","Ta r\u1eddi khu r\u1eebng n\xe0y kh\xf4ng c\xf2n l\xe0 k\u1ebb tr\u1ed1n n\u1ea1n. T\u1eeb nay, ta \u0111i \u0111\u1ec3 ch\u1ea5m d\u1ee9t v\xf2ng l\u1eb7p hi sinh.","N\u1ebfu g\u1ee5c t\u1ea1i \u0111\xe2y, t\xf4ng m\xf4n v\xe0 gia \u0111\xecnh ta s\u1ebd m\xe3i ch\u1ec9 l\xe0 m\u1ed9t d\xf2ng ch\u1eef trong bia m\u1ed9.")
B.aag=new A.br(B.abR,[B.akP,B.alq,B.akJ,B.al5,B.akR,B.akK],t.mS)
B.CG={r1:0,r10:1,r20:2,r30:3,r40:4,r50:5}
B.akT=new A.aT("T\xe0n t\xedch n\xe0y kh\xf4ng ch\u1ec9 ch\xe1y b\u1edfi l\u1eeda, n\xf3 ch\xe1y b\u1edfi tham v\u1ecdng c\u1ee7a k\u1ebb m\u1ea1nh.","\u0110\u1ecbch tr\u01b0\u1edbc m\u1eaft kh\xf4ng ph\u1ea3i l\xfac n\xe0o c\u0169ng l\xe0 g\u1ed1c r\u1ec5. Ta ph\u1ea3i nh\xecn xa h\u01a1n.",null)
B.akM=new A.aT("Ng\u01b0\u01a1i t\u1edbi mu\u1ed9n r\u1ed3i, c\xf4ng l\xfd \u1edf \u0111\xe2y \u0111\xe3 b\u1ecb \u0111em ra mua b\xe1n.","Ta b\u1eaft \u0111\u1ea7u hi\u1ec3u: \u0111\xfang sai ch\u01b0a t\u1eebng \u0111\u01a1n gi\u1ea3n.",null)
B.all=new A.aT("Ta t\u1eebng tin tr\u1eafng \u0111en r\xf5 r\xe0ng. Lo\u1ea1n th\u1ebf \u0111\xe3 d\u1ea1y ta c\xe1i gi\xe1 c\u1ee7a s\u1ef1 ng\xe2y th\u01a1.","C\xf3 nh\u1eefng ng\u01b0\u1eddi c\u1ea7m \u0111ao v\xec b\u1ecb \xe9p, kh\xf4ng ph\u1ea3i v\xec mu\u1ed1n gi\u1ebft.",null)
B.alw=new A.aT("N\u1ebfu tr\u1eadt t\u1ef1 n\xe0y c\u1ea7n ng\u01b0\u1eddi v\xf4 t\u1ed9i l\xe0m gi\xe1, ta kh\xf4ng ph\u1ee5c t\xf9ng.","Ta ch\u1ecdn con \u0111\u01b0\u1eddng kh\xf3: s\u1eeda sai, kh\xf4ng ch\u1ec9 tr\u1ea3 th\xf9.",null)
B.alb=new A.aT("Ng\u01b0\u01a1i mu\u1ed1n c\u1ee9u ng\u01b0\u1eddi? Tr\u01b0\u1edbc h\u1ebft h\u1ecdc c\xe1ch ch\u1ecbu \u0111\u1ef1ng s\u1ef1 th\u1eadt.","S\u1ef1 th\u1eadt \u0111au h\u01a1n ki\u1ebfm, nh\u01b0ng ch\u1ec9 n\xf3 m\u1edbi m\u1edf \u0111\u01b0\u1eddng.",null)
B.alg=new A.aT("Ng\u01b0\u01a1i \u0111\xf2i c\xf4ng b\u1eb1ng cho thi\xean h\u1ea1, v\u1eady ai \u0111\xf2i c\xf4ng b\u1eb1ng cho k\u1ebb b\u1ecb hi sinh?","Ch\u1ee9ng c\u1ee9 cu\u1ed1i \u0111\xe3 r\xf5: li\xean minh th\u01b0\u01a1ng h\u1ed9i c\xf9ng hai tr\u01b0\u1edfng l\xe3o ph\u1ea3n m\xf4n \u0111\xe3 k\xedch n\u1ed5 kho Vi\xeam Tinh \u0111\u1ec3 chi\u1ebfm Linh M\u1ea1ch Vi\xeam T\xe2m, r\u1ed3i \u0111\u1ed5 t\u1ed9i cho ngo\u1ea1i \u0111\u1ecbch. Ta r\u1eddi t\xe0n t\xedch n\xe0y v\u1edbi \u0111\xe1p \xe1n nguy\xean nh\xe2n, kh\xf4ng c\xf2n l\xe0 k\u1ebb tr\u1ea3 th\xf9 m\xf9 qu\xe1ng.","N\u1ebfu ta ng\xe3 \u1edf t\xe0n t\xedch n\xe0y, ta c\u0169ng s\u1ebd th\xe0nh m\u1ed9t h\xf2n tro v\xf4 danh.")
B.aai=new A.br(B.CG,[B.akT,B.akM,B.all,B.alw,B.alb,B.alg],t.mS)
B.alX=new A.aT("Bi\u1ec3n s\xe2u \u0111\xe8 n\u1eb7ng l\xean ng\u1ef1c, nh\u01b0 qu\xe1 kh\u1ee9 \u0111\xe8 n\u1eb7ng l\xean tim.","\xc1p l\u1ef1c bi\u1ec3n s\xe2u kh\xf4ng l\xe0m ta s\u1ee3 b\u1eb1ng vi\u1ec7c b\u1ecf m\u1eb7c ng\u01b0\u1eddi kh\xe1c ch\xecm xu\u1ed1ng.",null)
B.alQ=new A.aT("\u1ede \u0111\xe2y, ch\u1ec9 k\u1ebb d\xe1m th\u1edf trong tuy\u1ec7t v\u1ecdng m\u1edbi \u0111i ti\u1ebfp \u0111\u01b0\u1ee3c.","Ta \u0111\xe3 quen \u0111au, nh\u01b0ng ch\u01b0a t\u1eebng quen nh\xecn d\xe2n th\u01b0\u1eddng ch\u1ecbu \u0111au.",null)
B.alr=new A.aT("Ng\u01b0\u01a1i c\u1ee9u \u0111\u01b0\u1ee3c m\xecnh, ch\u01b0a ch\u1eafc c\u1ee9u \u0111\u01b0\u1ee3c thi\xean h\u1ea1.","N\u1ebfu s\u1ee9c m\u1ea1nh ch\u1ec9 c\u1ee9u m\u1ed9t m\xecnh ta, th\xec s\u1ee9c m\u1ea1nh \u0111\xf3 v\xf4 ngh\u0129a.",null)
B.al6=new A.aT("S\u1ef1 th\u1eadt v\u1ec1 s\u01b0 ph\u1ee5 ng\u01b0\u01a1i \u0111ang \u1edf ph\xeda tr\u01b0\u1edbc. Ng\u01b0\u01a1i c\xf3 d\xe1m \u0111\u1ed1i di\u1ec7n kh\xf4ng?","Ng\u01b0\u1eddi \u0111i tr\u01b0\u1edbc \u0111\xe3 ng\xe3 \u0111\u1ec3 ta c\xf2n l\u1ef1a ch\u1ecdn. Ta kh\xf4ng \u0111\u01b0\u1ee3c ph\xe9p s\u1ed1ng h\xe8n.",null)
B.alG=new A.aT("M\u1ed9t quy\u1ebft \u0111\u1ecbnh c\u1ee7a ng\u01b0\u01a1i, tri\u1ec7u ng\u01b0\u1eddi s\u1ebd ph\u1ea3i tr\u1ea3 gi\xe1.","Tr\u01b0\u1edfng th\xe0nh l\xe0 d\xe1m tr\u1ea3 gi\xe1 cho \u0111i\u1ec1u m\xecnh tin, kh\xf4ng ph\u1ea3i n\xe9 tr\xe1nh c\xe1i gi\xe1 \u1ea5y.",null)
B.ald=new A.aT("Ch\u1ecdn \u0111i, t\u1ea3n tu: an to\xe0n cho s\u1ed1 \xedt, hay \u0111au \u0111\u1edbn \u0111\u1ec3 m\u1edf m\u1ed9t t\u01b0\u01a1ng lai m\u1edbi cho t\u1ea5t c\u1ea3?","Phong \u1ea5n Enkavia \u0111\xe3 m\u1edf, to\xe0n b\u1ed9 k\xfd l\u1ee5c ph\u1ea3n b\u1ed9i \u0111\u01b0\u1ee3c c\xf4ng b\u1ed1 tr\u01b0\u1edbc c\xe1c t\xf4ng m\xf4n. T\u1eeb \u0111\xe2y v\xf2ng l\u1eb7p ch\xe9m gi\u1ebft b\u1ecb b\u1ebb g\xe3y: k\u1ebb ch\u1ee7 m\u01b0u b\u1ecb truy n\xe3, d\xe2n th\u01b0\u1eddng \u0111\u01b0\u1ee3c l\u1eadp \u01b0\u1edbc b\u1ea3o h\u1ed9. Ta kh\xf4ng th\u1eafng ch\u1ec9 cho ri\xeang m\xecnh, m\xe0 \u0111\u1ec3 kh\xe9p l\u1ea1i m\u1ed9t ch\u01b0\u01a1ng \u0111\u1eabm m\xe1u.","N\u1ebfu ta g\u1ee5c xu\u1ed1ng, th\u1ebf gi\u1edbi n\xe0y s\u1ebd l\u1ea1i r\u01a1i v\xe0o tay k\u1ebb ch\u1ec9 bi\u1ebft ch\u1ecdn ph\u1ea7n d\u1ec5.")
B.aaj=new A.br(B.CG,[B.alX,B.alQ,B.alr,B.al6,B.alG,B.ald],t.mS)
B.aal=new A.br(B.CI,[B.aag,B.aai,B.aaj],t.C2)
B.abD={starter_forest:0,blazing_ruins:1,enkavia:2,reverse_world:3,sealed_void:4}
B.akG=new A.qY("Ch\u01b0\u01a1ng 1 - R\u1eebng T\xe2n Th\u1ee7","R\u1eebng c\u0169 v\u1eabn xanh, ch\u1ec9 l\xf2ng ng\u01b0\u1eddi \u0111\xe3 \u0111\u1ed5i m\xe0u. Ta tr\u1edf l\u1ea1i n\u01a1i nh\u1eadp m\xf4n n\u0103m x\u01b0a sau l\u1ec5 tang song th\xe2n \u0111\xe3 m\xe3n th\u1ecd, kh\xf4ng c\xf2n l\xe0 \u0111\u1ec7 t\u1eed c\u0169 m\xe0 l\xe0 k\u1ebb s\u1ed1ng s\xf3t \u0111i gi\u1eef l\u1eddi h\u1ee9a mu\u1ed9n v\u1edbi gia \u0111\xecnh.")
B.akH=new A.qY("Ch\u01b0\u01a1ng 2 - T\xe0n T\xedch Vi\xeam","T\xe0n t\xedch n\xe0y ch\xe1y kh\xf4ng ch\u1ec9 b\u1edfi l\u1eeda, m\xe0 b\u1edfi cu\u1ed9c tranh \u0111o\u1ea1t Linh M\u1ea1ch Vi\xeam T\xe2m gi\u1eefa th\u01b0\u01a1ng h\u1ed9i v\xe0 n\u1ed9i ph\u1ea3n trong c\xe1c t\xf4ng m\xf4n. Ta \u0111i s\xe2u v\xe0o tro t\xe0n \u0111\u1ec3 l\u1ea5y ch\u1ee9ng c\u1ee9 cu\u1ed1i, v\u1ea1ch r\xf5 ai \u0111\xe3 ch\xe2m ng\xf2i chi\u1ebfn cu\u1ed9c h\u1ee7y di\u1ec7t t\xf4ng m\xf4n c\u1ee7a ta.")
B.akE=new A.qY("Ch\u01b0\u01a1ng 3 - \u0110\xe1y Bi\u1ec3n Enkavia","Bi\u1ec3n s\xe2u Enkavia c\u1ea5t gi\u1eef phong \u1ea5n k\xfd \u1ee9c v\u1ec1 to\xe0n b\u1ed9 v\u1ee5 ph\u1ea3n b\u1ed9i. N\u1ebfu m\u1edf \u0111\u01b0\u1ee3c phong \u1ea5n n\xe0y v\xe0 c\xf4ng b\u1ed1 tr\u01b0\u1edbc thi\xean h\u1ea1, ta c\xf3 th\u1ec3 kh\xe9p l\u1ea1i v\xf2ng l\u1eb7p ch\xe9m gi\u1ebft, m\u1edf ra m\u1ed9t tr\u1eadt t\u1ef1 m\u1edbi n\u01a1i k\u1ebb y\u1ebfu kh\xf4ng c\xf2n b\u1ecb \u0111em l\xe0m v\u1eadt hi sinh.")
B.akI=new A.qY("Ch\u01b0\u01a1ng 4 - Th\u1ebf Gi\u1edbi \u0110\u1ea3o Ng\u01b0\u1ee3c","Sau khi tho\xe1t kh\u1ecfi Enkavia, thuy\u1ec1n c\u1ee7a ta v\u1eeba r\u1eddi m\u1eb7t bi\u1ec3n ch\u01b0a bao xa th\xec to\xe0n b\u1ed9 h\u1ea3i l\u01b0u b\u1ed7ng xo\u1eafn l\u1ea1i th\xe0nh m\u1ed9t l\u1ed7 h\u1ed5ng kh\xf4ng gian. Khi m\u1edf m\u1eaft, tr\u01b0\u1edbc m\u1eb7t ta l\xe0 m\u1ed9t th\u1ebf gi\u1edbi \u0111\u1ea3o ng\u01b0\u1ee3c: bi\u1ec3n treo tr\xean tr\u1eddi, th\xe0nh qu\xe1ch l\u1eadt \xfap, m\xf9a m\xe0ng ch\u1ea3y ng\u01b0\u1ee3c v\u1ec1 tro b\u1ee5i, c\xf2n nh\u1eefng con ng\u01b0\u1eddi m\u1eafc k\u1eb9t \u1edf \u0111\xe2y th\xec v\u1eeba s\u1ed1ng nh\u01b0 th\u1eadt, v\u1eeba nh\u01b0 \u0111ang b\u1ecb k\xfd \u1ee9c c\u1ee7a ch\xednh m\xecnh n\xedu l\u1ea1i. Nh\u01b0ng \u1edf Th\u1ebf Gi\u1edbi \u0110\u1ea3o Ng\u01b0\u1ee3c, m\u1ed7i node ch\u1ec9 cho ng\u01b0\u1eddi ch\u01a1i d\xf9ng \u0111\xfang 1 trong 5 k\u1ef9 n\u0103ng, v\xe0 kho\xe1 n\xe0y l\xe0 c\u1ed1 \u0111\u1ecbnh theo node. Mu\u1ed1n r\u1eddi kh\u1ecfi n\u01a1i n\xe0y, ta ch\u1ec9 c\xf2n c\xe1ch \u0111i t\u1edbi t\u1eadn c\xf9ng, l\u1ea7n theo t\u1eebng phi\u1ebfn \u0111\xe1 c\u1ed5 v\xe0 nghe h\u1ebft nh\u1eefng c\xe2u chuy\u1ec7n ch\u01b0a ai d\xe1m kh\xe9p l\u1ea1i.")
B.akF=new A.qY("Ch\u01b0\u01a1ng 5 - H\u01b0 V\u1ef1c Phong \u1ea4n (S\u1eafp M\u1edf)","C\xe1nh c\u1ed5ng H\u01b0 V\u1ef1c v\u1eabn b\u1ecb ni\xeam phong. Khi th\u1eddi \u0111i\u1ec3m \u0111\u1ebfn, h\xe0nh tr\xecnh k\u1ebf ti\u1ebfp s\u1ebd m\u1edf ra c\xf9ng ch\xe2n t\u01b0\u1edbng sau c\xf9ng.")
